/*!
 * QRCode generator (compact, MIT) — adapted from Project Nayuki's QR Code generator
 * https://www.nayuki.io/page/qr-code-generator-library
 * Trimmed for browser use. Generates QR Code matrix; we render to canvas.
 */
var QRCode=(function(){
  function QrSegment(mode,numChars,bitData){this.mode=mode;this.numChars=numChars;this.bitData=bitData;}
  QrSegment.makeBytes=function(data){var bb=[];for(var i=0;i<data.length;i++){var c=data.charCodeAt(i);if(c<0x80){bb.push(c);}else if(c<0x800){bb.push(0xC0|(c>>6));bb.push(0x80|(c&0x3F));}else if(c<0xD800||c>=0xE000){bb.push(0xE0|(c>>12));bb.push(0x80|((c>>6)&0x3F));bb.push(0x80|(c&0x3F));}else{bb.push(0xF0);}} var bits=[];bb.forEach(function(b){for(var j=7;j>=0;j--)bits.push((b>>j)&1);});return new QrSegment(QrSegment.Mode.BYTE,bb.length,bits);};
  QrSegment.Mode={NUMERIC:{cciBits:[10,12,14],modeBits:1},ALPHANUMERIC:{cciBits:[9,11,13],modeBits:2},BYTE:{cciBits:[8,16,16],modeBits:4},KANJI:{cciBits:[8,10,12],modeBits:8}};
  QrSegment.getTotalBits=function(segs,version){var result=0;for(var i=0;i<segs.length;i++){var seg=segs[i];var ccbits=seg.mode.cciBits[Math.floor((version+7)/17)];if(seg.numChars>=(1<<ccbits))return Infinity;result+=4+ccbits+seg.bitData.length;}return result;};

  var ECC={LOW:{ordinal:0,formatBits:1},MEDIUM:{ordinal:1,formatBits:0},QUARTILE:{ordinal:2,formatBits:3},HIGH:{ordinal:3,formatBits:2}};

  function QrCode(version,ecl,dataCodewords,msk){
    this.version=version;this.errorCorrectionLevel=ecl;this.size=version*4+17;this.mask=msk;
    var modules=[],isFunction=[];
    for(var i=0;i<this.size;i++){var row=[],rowF=[];for(var j=0;j<this.size;j++){row.push(false);rowF.push(false);}modules.push(row);isFunction.push(rowF);}
    this.modules=modules;this.isFunction=isFunction;
    this.drawFunctionPatterns();
    var allCodewords=this.addEccAndInterleave(dataCodewords);
    this.drawCodewords(allCodewords);
    if(msk==-1){var minPenalty=1000000000;for(var m=0;m<8;m++){this.applyMask(m);this.drawFormatBits(m);var p=this.getPenaltyScore();if(p<minPenalty){msk=m;minPenalty=p;}this.applyMask(m);}}
    this.mask=msk;this.applyMask(msk);this.drawFormatBits(msk);
  }

  QrCode.encodeText=function(text,ecl){
    var segs=[QrSegment.makeBytes(text)];return QrCode.encodeSegments(segs,ecl);
  };
  QrCode.encodeSegments=function(segs,ecl,minVer,maxVer,mask,boost){
    minVer=minVer||1;maxVer=maxVer||40;mask=mask==null?-1:mask;boost=boost!==false;
    var version,dataUsedBits;
    for(version=minVer;;version++){
      var dataCapacityBits=QrCode.getNumDataCodewords(version,ecl)*8;
      var usedBits=QrSegment.getTotalBits(segs,version);
      if(usedBits<=dataCapacityBits){dataUsedBits=usedBits;break;}
      if(version>=maxVer)throw"Data too long";
    }
    if(boost){[ECC.MEDIUM,ECC.QUARTILE,ECC.HIGH].forEach(function(newEcl){if(dataUsedBits<=QrCode.getNumDataCodewords(version,newEcl)*8)ecl=newEcl;});}
    var bb=[];
    segs.forEach(function(seg){appendBits(seg.mode.modeBits,4,bb);appendBits(seg.numChars,seg.mode.cciBits[Math.floor((version+7)/17)],bb);seg.bitData.forEach(function(b){bb.push(b);});});
    var dataCapacityBits=QrCode.getNumDataCodewords(version,ecl)*8;
    appendBits(0,Math.min(4,dataCapacityBits-bb.length),bb);
    appendBits(0,(8-bb.length%8)%8,bb);
    for(var padByte=0xEC;bb.length<dataCapacityBits;padByte^=0xEC^0x11)appendBits(padByte,8,bb);
    var dataCodewords=[];for(var i=0;i<bb.length;i+=8){var v=0;for(var j=0;j<8;j++)v|=bb[i+j]<<(7-j);dataCodewords.push(v);}
    return new QrCode(version,ecl,dataCodewords,mask);
  };

  function appendBits(val,len,bb){for(var i=len-1;i>=0;i--)bb.push((val>>i)&1);}

  QrCode.prototype.drawFunctionPatterns=function(){
    for(var i=0;i<this.size;i++){this.setFunctionModule(6,i,i%2==0);this.setFunctionModule(i,6,i%2==0);}
    this.drawFinderPattern(3,3);this.drawFinderPattern(this.size-4,3);this.drawFinderPattern(3,this.size-4);
    var alignPosList=this.getAlignmentPatternPositions();var n=alignPosList.length;
    for(var i=0;i<n;i++)for(var j=0;j<n;j++){if(!((i==0&&j==0)||(i==0&&j==n-1)||(i==n-1&&j==0)))this.drawAlignmentPattern(alignPosList[i],alignPosList[j]);}
    this.drawFormatBits(0);this.drawVersion();
  };
  QrCode.prototype.drawFormatBits=function(mask){
    var data=this.errorCorrectionLevel.formatBits<<3|mask;var rem=data;
    for(var i=0;i<10;i++)rem=(rem<<1)^((rem>>>9)*0x537);
    var bits=(data<<10|rem)^0x5412;
    for(var i=0;i<=5;i++)this.setFunctionModule(8,i,((bits>>i)&1)!=0);
    this.setFunctionModule(8,7,((bits>>6)&1)!=0);this.setFunctionModule(8,8,((bits>>7)&1)!=0);this.setFunctionModule(7,8,((bits>>8)&1)!=0);
    for(var i=9;i<15;i++)this.setFunctionModule(14-i,8,((bits>>i)&1)!=0);
    for(var i=0;i<8;i++)this.setFunctionModule(this.size-1-i,8,((bits>>i)&1)!=0);
    for(var i=8;i<15;i++)this.setFunctionModule(8,this.size-15+i,((bits>>i)&1)!=0);
    this.setFunctionModule(8,this.size-8,true);
  };
  QrCode.prototype.drawVersion=function(){
    if(this.version<7)return;var rem=this.version;
    for(var i=0;i<12;i++)rem=(rem<<1)^((rem>>>11)*0x1F25);
    var bits=this.version<<12|rem;
    for(var i=0;i<18;i++){var bit=((bits>>i)&1)!=0;var a=this.size-11+i%3,b=Math.floor(i/3);this.setFunctionModule(a,b,bit);this.setFunctionModule(b,a,bit);}
  };
  QrCode.prototype.drawFinderPattern=function(x,y){
    for(var dy=-4;dy<=4;dy++)for(var dx=-4;dx<=4;dx++){var dist=Math.max(Math.abs(dx),Math.abs(dy));var xx=x+dx,yy=y+dy;if(0<=xx&&xx<this.size&&0<=yy&&yy<this.size)this.setFunctionModule(xx,yy,dist!=2&&dist!=4);}
  };
  QrCode.prototype.drawAlignmentPattern=function(x,y){
    for(var dy=-2;dy<=2;dy++)for(var dx=-2;dx<=2;dx++)this.setFunctionModule(x+dx,y+dy,Math.max(Math.abs(dx),Math.abs(dy))!=1);
  };
  QrCode.prototype.setFunctionModule=function(x,y,isDark){this.modules[y][x]=isDark;this.isFunction[y][x]=true;};
  QrCode.prototype.getAlignmentPatternPositions=function(){
    if(this.version==1)return[];
    var numAlign=Math.floor(this.version/7)+2;
    var step=(this.version==32)?26:Math.ceil((this.version*4+4)/(numAlign*2-2))*2;
    var result=[6];for(var pos=this.size-7;result.length<numAlign;pos-=step)result.splice(1,0,pos);
    return result;
  };
  QrCode.getNumRawDataModules=function(ver){
    var result=(16*ver+128)*ver+64;
    if(ver>=2){var numAlign=Math.floor(ver/7)+2;result-=(25*numAlign-10)*numAlign-55;if(ver>=7)result-=36;}
    return result;
  };
  QrCode.getNumDataCodewords=function(ver,ecl){return Math.floor(QrCode.getNumRawDataModules(ver)/8)-QrCode.ECC_CODEWORDS_PER_BLOCK[ecl.ordinal][ver]*QrCode.NUM_ERROR_CORRECTION_BLOCKS[ecl.ordinal][ver];};

  QrCode.prototype.addEccAndInterleave=function(data){
    var ver=this.version;var ecl=this.errorCorrectionLevel;
    var numBlocks=QrCode.NUM_ERROR_CORRECTION_BLOCKS[ecl.ordinal][ver];
    var blockEccLen=QrCode.ECC_CODEWORDS_PER_BLOCK[ecl.ordinal][ver];
    var rawCodewords=Math.floor(QrCode.getNumRawDataModules(ver)/8);
    var numShortBlocks=numBlocks-rawCodewords%numBlocks;
    var shortBlockLen=Math.floor(rawCodewords/numBlocks);
    var blocks=[];var rsDiv=QrCode.reedSolomonComputeDivisor(blockEccLen);
    for(var i=0,k=0;i<numBlocks;i++){var dat=data.slice(k,k+shortBlockLen-blockEccLen+(i<numShortBlocks?0:1));k+=dat.length;var ecc=QrCode.reedSolomonComputeRemainder(dat,rsDiv);if(i<numShortBlocks)dat.push(0);blocks.push(dat.concat(ecc));}
    var result=[];
    for(var i=0;i<blocks[0].length;i++){blocks.forEach(function(block,j){if(i!=shortBlockLen-blockEccLen||j>=numShortBlocks)result.push(block[i]);});}
    return result;
  };
  QrCode.prototype.drawCodewords=function(data){
    var i=0;
    for(var right=this.size-1;right>=1;right-=2){
      if(right==6)right=5;
      for(var vert=0;vert<this.size;vert++){
        for(var j=0;j<2;j++){
          var x=right-j;var upward=((right+1)&2)==0;var y=upward?this.size-1-vert:vert;
          if(!this.isFunction[y][x]&&i<data.length*8){this.modules[y][x]=((data[i>>>3]>>>(7-(i&7)))&1)!=0;i++;}
        }
      }
    }
  };
  QrCode.prototype.applyMask=function(mask){
    for(var y=0;y<this.size;y++){for(var x=0;x<this.size;x++){var invert;switch(mask){case 0:invert=(x+y)%2==0;break;case 1:invert=y%2==0;break;case 2:invert=x%3==0;break;case 3:invert=(x+y)%3==0;break;case 4:invert=(Math.floor(x/3)+Math.floor(y/2))%2==0;break;case 5:invert=x*y%2+x*y%3==0;break;case 6:invert=(x*y%2+x*y%3)%2==0;break;case 7:invert=((x+y)%2+x*y%3)%2==0;break;}if(!this.isFunction[y][x]&&invert)this.modules[y][x]=!this.modules[y][x];}}
  };
  QrCode.prototype.getPenaltyScore=function(){
    var result=0;var size=this.size;var mods=this.modules;
    for(var y=0;y<size;y++){var run=0,col=false;for(var x=0;x<size;x++){if(mods[y][x]==col){run++;if(run==5)result+=3;else if(run>5)result++;}else{col=mods[y][x];run=1;}}}
    for(var x=0;x<size;x++){var run=0,col=false;for(var y=0;y<size;y++){if(mods[y][x]==col){run++;if(run==5)result+=3;else if(run>5)result++;}else{col=mods[y][x];run=1;}}}
    for(var y=0;y<size-1;y++)for(var x=0;x<size-1;x++){var c=mods[y][x];if(c==mods[y][x+1]&&c==mods[y+1][x]&&c==mods[y+1][x+1])result+=3;}
    var dark=0;mods.forEach(function(row){row.forEach(function(c){if(c)dark++;});});var total=size*size;var k=Math.ceil(Math.abs(dark*20-total*10)/total)-1;result+=k*10;
    return result;
  };
  QrCode.reedSolomonComputeDivisor=function(degree){
    var result=[];for(var i=0;i<degree-1;i++)result.push(0);result.push(1);var root=1;
    for(var i=0;i<degree;i++){for(var j=0;j<result.length;j++){result[j]=QrCode.reedSolomonMultiply(result[j],root);if(j+1<result.length)result[j]^=result[j+1];}root=QrCode.reedSolomonMultiply(root,2);}
    return result;
  };
  QrCode.reedSolomonComputeRemainder=function(data,divisor){
    var result=divisor.map(function(){return 0;});
    data.forEach(function(b){var factor=b^result.shift();result.push(0);divisor.forEach(function(d,i){result[i]^=QrCode.reedSolomonMultiply(d,factor);});});
    return result;
  };
  QrCode.reedSolomonMultiply=function(x,y){var z=0;for(var i=7;i>=0;i--){z=(z<<1)^((z>>>7)*0x11D);z^=((y>>>i)&1)*x;}return z;};

  QrCode.ECC_CODEWORDS_PER_BLOCK=[
    [-1,7,10,15,20,26,18,20,24,30,18,20,24,26,30,22,24,28,30,28,28,28,28,30,30,26,28,26,28,28,30,30,30,30,30,30,30,30,30,30,30],
    [-1,10,16,26,18,24,16,18,22,22,26,30,22,22,24,24,28,28,26,26,26,26,28,28,28,28,28,28,28,28,28,28,28,28,28,28,28,28,28,28,28],
    [-1,13,22,18,26,18,24,18,22,20,24,28,26,24,20,30,24,28,28,26,30,28,30,30,30,30,28,30,30,30,30,30,30,30,30,30,30,30,30,30,30],
    [-1,17,28,22,16,22,28,26,26,24,28,24,28,22,24,24,30,28,28,26,28,30,24,30,30,30,30,30,30,30,30,30,30,30,30,30,30,30,30,30,30]
  ];
  QrCode.NUM_ERROR_CORRECTION_BLOCKS=[
    [-1,1,1,1,1,1,2,2,2,2,4,4,4,4,4,6,6,6,6,7,8,8,9,9,10,12,12,13,14,15,16,17,18,19,19,20,21,22,24,25,25],
    [-1,1,1,1,2,2,4,4,4,5,5,5,8,9,9,10,10,11,13,14,16,17,17,18,20,21,23,25,26,28,29,31,33,35,37,38,40,43,45,47,49],
    [-1,1,1,2,2,4,4,6,6,8,8,8,10,12,16,12,17,16,18,21,20,23,23,25,27,29,34,34,35,38,40,43,45,48,51,53,56,59,62,65,68],
    [-1,1,1,2,4,4,4,5,6,8,8,11,11,16,16,18,16,19,21,25,25,25,34,30,32,35,37,40,42,45,48,51,54,57,60,63,66,70,74,77,81]
  ];
  QrCode.ECC=ECC;

  /* Render to canvas */
  function renderCanvas(text,canvas,opts){
    opts=opts||{};
    var qr=QrCode.encodeText(text,opts.ecc||ECC.MEDIUM);
    var size=qr.size;var scale=opts.scale||4;var border=opts.border||2;
    var dim=(size+border*2)*scale;
    canvas.width=dim;canvas.height=dim;
    var ctx=canvas.getContext('2d');ctx.fillStyle=opts.light||'#fff';ctx.fillRect(0,0,dim,dim);ctx.fillStyle=opts.dark||'#000';
    for(var y=0;y<size;y++)for(var x=0;x<size;x++)if(qr.modules[y][x])ctx.fillRect((x+border)*scale,(y+border)*scale,scale,scale);
    return canvas;
  }

  return {
    toCanvas:function(canvas,text,opts){return renderCanvas(text,canvas,opts);},
    ECC:ECC
  };
})();
